#[cfg(test)]
mod tests {
    use super::*;

    struct MockGenerator;
    #[async_trait]
    impl GenerationEngine for MockGenerator {
        fn name(&self) -> &str { "mock" }
        async fn generate(
            &self,
            _system_prompt: &str,
            user_message: &str,
        ) -> corvia_common::errors::Result<crate::rag_types::GenerationResult> {
            Ok(crate::rag_types::GenerationResult {
                text: format!("Answer to: {user_message}"),
                model: "mock-model".into(),
                input_tokens: user_message.len() / 4,
                output_tokens: 10,
            })
        }
        fn context_window(&self) -> usize { 4096 }
    }

    #[tokio::test]
    async fn test_generation_engine_mock() {
        let gen = MockGenerator;
        assert_eq!(gen.name(), "mock");
        assert_eq!(gen.context_window(), 4096);
        let result = gen.generate("system", "What is auth?").await.unwrap();
        assert_eq!(result.text, "Answer to: What is auth?");
        assert_eq!(result.model, "mock-model");
    }
}
